            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(CaptureInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
    }
}

pub async fn post_delete_inbox_item(
